// Generated by forge proof from verify-proof-parser.md, verify-run-checks.md, verify-pr-creation.md
import { describe, test, expect, afterEach, beforeEach, spyOn } from 'bun:test';
import { promises as fs } from 'fs';
import path from 'path';
import os from 'os';
import { readProofManifest, detectTestRunner, buildPRBody, createVerifyPR, runVerify } from './proof-runner.js';
import type { VerifyOptions, VerifyResult, ProofManifest, ProofManifestEntry, ForgeResult } from './types.js';

// ── Helpers ──────────────────────────────────────────────────

let tmpDirs: string[] = [];

async function makeTmpDir(): Promise<string> {
  const raw = await fs.mkdtemp(path.join(os.tmpdir(), 'forge-verify-test-'));
  const dir = await fs.realpath(raw);
  tmpDirs.push(dir);
  return dir;
}

afterEach(async () => {
  for (const d of tmpDirs) {
    await fs.rm(d, { recursive: true, force: true }).catch(() => {});
  }
  tmpDirs = [];
  // Reset process.exitCode after tests that set it
  process.exitCode = 0;
});

function makeManifest(overrides: Partial<ProofManifest> = {}): ProofManifest {
  return {
    generatedAt: new Date().toISOString(),
    specDir: 'specs/',
    entries: [
      { specFile: 'auth.md', category: 'unit', testFile: '/abs/path/auth.test.ts', description: 'Auth tests' },
    ],
    manualCheckCount: 0,
    ...overrides,
  };
}

function makeEntry(overrides: Partial<ProofManifestEntry> = {}): ProofManifestEntry {
  return {
    specFile: 'feature.md',
    category: 'unit',
    testFile: 'feature.test.ts',
    description: 'Feature tests',
    ...overrides,
  };
}

function makeResult(overrides: Partial<VerifyResult> = {}): VerifyResult {
  return {
    testFile: 'auth.test.ts',
    status: 'pass',
    exitCode: 0,
    stderr: '',
    durationSeconds: 1.5,
    ...overrides,
  };
}

async function writeManifest(dir: string, manifest: ProofManifest): Promise<void> {
  await fs.writeFile(path.join(dir, 'manifest.json'), JSON.stringify(manifest, null, 2));
}

async function writeManual(dir: string, content: string): Promise<void> {
  await fs.writeFile(path.join(dir, 'manual.md'), content);
}

/** Create a minimal bun test file that passes */
async function writePassingTest(filePath: string): Promise<void> {
  await fs.mkdir(path.dirname(filePath), { recursive: true });
  await fs.writeFile(filePath, `
import { test, expect } from 'bun:test';
test('passes', () => { expect(1 + 1).toBe(2); });
`);
}

/** Create a minimal bun test file that fails */
async function writeFailingTest(filePath: string): Promise<void> {
  await fs.mkdir(path.dirname(filePath), { recursive: true });
  await fs.writeFile(filePath, `
import { test, expect } from 'bun:test';
test('fails', () => { expect(1).toBe(2); });
`);
}

/**
 * Set up a project dir with bun.lockb so detectTestRunner returns 'bun test'.
 * Creates .forge dir structure and proof dir with manifest.
 */
async function setupProjectWithProofs(opts: {
  entries: ProofManifestEntry[];
  manualContent?: string;
}): Promise<{ cwd: string; proofDir: string }> {
  const cwd = await makeTmpDir();
  const proofDir = path.join(cwd, '.forge', 'proofs', 'test-proof');
  await fs.mkdir(proofDir, { recursive: true });

  // Make it look like a bun project
  await fs.writeFile(path.join(cwd, 'bun.lockb'), '');

  // Write manifest
  await writeManifest(proofDir, makeManifest({ entries: opts.entries }));

  // Write manual.md if content provided
  if (opts.manualContent) {
    await writeManual(proofDir, opts.manualContent);
  }

  return { cwd, proofDir };
}

