// ── buildPRBody ──────────────────────────────────────────────

describe('buildPRBody', () => {
  test('starts with ## Summary section', () => {
    const body = buildPRBody([makeResult()], []);
    expect(body.startsWith('## Summary')).toBe(true);
  });

  test('generates summary table with correct columns', () => {
    const body = buildPRBody([makeResult()], []);
    expect(body).toContain('| File | Status | Duration |');
    expect(body).toContain('|------|--------|----------|');
  });

  test('maps pass/fail/skipped statuses correctly', () => {
    const results: VerifyResult[] = [
      makeResult({ testFile: 'auth.test.ts', status: 'pass', durationSeconds: 1.2 }),
      makeResult({ testFile: 'api.test.ts', status: 'fail', durationSeconds: 3.5 }),
      makeResult({ testFile: 'missing.test.ts', status: 'skipped', durationSeconds: undefined }),
    ];

    const body = buildPRBody(results, []);
    expect(body).toContain('| auth.test.ts | PASS | 1.2s |');
    expect(body).toContain('| api.test.ts | FAIL | 3.5s |');
    expect(body).toContain('| missing.test.ts | SKIPPED | N/A |');
  });

  test('formats duration with one decimal place', () => {
    const body = buildPRBody([makeResult({ durationSeconds: 12.345 })], []);
    expect(body).toContain('12.3s');
  });

  test('shows N/A for undefined duration', () => {
    const body = buildPRBody([makeResult({ durationSeconds: undefined })], []);
    expect(body).toContain('N/A');
  });

  test('includes human verification section when steps provided', () => {
    const humanSteps = [
      '- Check the login page renders correctly',
      '- Verify OAuth redirect works',
    ];

    const body = buildPRBody([makeResult()], humanSteps);
    expect(body).toContain('## Human Verification');
    expect(body).toContain('- [ ] Check the login page renders correctly');
    expect(body).toContain('- [ ] Verify OAuth redirect works');
  });

  test('omits human verification section when no steps', () => {
    const body = buildPRBody([makeResult()], []);
    expect(body).not.toContain('## Human Verification');
  });

  test('strips leading dash markers from human steps', () => {
    const body = buildPRBody([makeResult()], ['- Manually check X']);
    expect(body).toContain('- [ ] Manually check X');
    expect(body).not.toContain('- [ ] - ');
  });

  test('strips leading asterisk markers from human steps', () => {
    const body = buildPRBody([makeResult()], ['* Verify Y']);
    expect(body).toContain('- [ ] Verify Y');
    expect(body).not.toContain('- [ ] * ');
  });

  test('strips numbered list markers from human steps', () => {
    const body = buildPRBody([makeResult()], ['1. Check Z']);
    expect(body).toContain('- [ ] Check Z');
    expect(body).not.toContain('- [ ] 1. ');
  });

  test('handles steps without markers', () => {
    const body = buildPRBody([makeResult()], ['Plain text step']);
    expect(body).toContain('- [ ] Plain text step');
  });

  test('handles empty results array', () => {
    const body = buildPRBody([], []);
    expect(body).toContain('## Summary');
    expect(body).toContain('| File | Status | Duration |');
  });

  test('result body is trimmed (no trailing whitespace)', () => {
    const body = buildPRBody([makeResult()], []);
    expect(body).toBe(body.trimEnd());
  });

  test('one table row per test file', () => {
    const results = [
      makeResult({ testFile: 'a.test.ts' }),
      makeResult({ testFile: 'b.test.ts' }),
      makeResult({ testFile: 'c.test.ts' }),
    ];
    const body = buildPRBody(results, []);
    // Count data rows (exclude header and separator)
    const tableRows = body.split('\n').filter(l =>
      l.startsWith('| ') && !l.startsWith('| File') && !l.startsWith('|---'),
    );
    expect(tableRows).toHaveLength(3);
  });

  test('handles many human steps', () => {
    const steps = Array.from({ length: 20 }, (_, i) => `- Step ${i + 1}`);
    const body = buildPRBody([makeResult()], steps);
    expect(body).toContain('## Human Verification');
    // All 20 steps should be present
    for (let i = 1; i <= 20; i++) {
      expect(body).toContain(`- [ ] Step ${i}`);
    }
  });
});

// ── createVerifyPR ───────────────────────────────────────────

describe('createVerifyPR', () => {
  test('skips silently when no results', async () => {
    const dir = await makeTmpDir();
    // Should not throw, just return silently
    await createVerifyPR(dir, [], [], dir, { quiet: true });
  });

  test('skips PR when any test fails and sets exitCode to 1', async () => {
    const dir = await makeTmpDir();
    const results = [
      makeResult({ status: 'pass' }),
      makeResult({ testFile: 'fail.test.ts', status: 'fail', exitCode: 1, stderr: 'assertion error' }),
    ];

    await createVerifyPR(dir, results, [], dir, { quiet: true });
    expect(process.exitCode).toBe(1);
  });

  test('skips PR when all tests fail', async () => {
    const dir = await makeTmpDir();
    const results = [
      makeResult({ status: 'fail', exitCode: 1 }),
      makeResult({ testFile: 'b.test.ts', status: 'fail', exitCode: 1 }),
    ];

    await createVerifyPR(dir, results, [], dir, { quiet: true });
    expect(process.exitCode).toBe(1);
  });

  test('does not set exitCode when all tests pass', async () => {
    const dir = await makeTmpDir();
    const results = [makeResult({ status: 'pass' })];

    // This will try to call gh and fail (not in git repo), but should handle gracefully
    await createVerifyPR(dir, results, [], dir, { quiet: true });
    // exitCode should not be 1 (gh failure is caught gracefully)
    expect(process.exitCode).not.toBe(1);
  });

  test('skipped results do not count as failures', async () => {
    const dir = await makeTmpDir();
    const results = [
      makeResult({ status: 'pass' }),
      makeResult({ testFile: 'skip.test.ts', status: 'skipped' }),
    ];

    // skipped is not 'fail', so PR should be attempted (gh will fail gracefully)
    await createVerifyPR(dir, results, [], dir, { quiet: true });
    expect(process.exitCode).not.toBe(1);
  });

  test('dry-run mode does not create PR and does not throw', async () => {
    const dir = await makeTmpDir();
    const results = [makeResult({ status: 'pass' })];

    // In dry-run mode, should return without error even without gh
    await createVerifyPR(dir, results, [], dir, { dryRun: true, quiet: true });
    expect(process.exitCode).not.toBe(1);
  });

  test('dry-run with quiet mode is completely silent', async () => {
    const dir = await makeTmpDir();
    const results = [makeResult({ status: 'pass' })];
    const logSpy = spyOn(console, 'log').mockImplementation(() => {});

    await createVerifyPR(dir, results, [], dir, { dryRun: true, quiet: true });

    // Should not have printed anything
    expect(logSpy).not.toHaveBeenCalled();
    logSpy.mockRestore();
  });

  test('dry-run without quiet prints PR title and body', async () => {
    const dir = await makeTmpDir();
    const proofDir = path.join(dir, 'my-feature');
    await fs.mkdir(proofDir, { recursive: true });
    const results = [makeResult({ status: 'pass' })];
    const logged: string[] = [];
    const logSpy = spyOn(console, 'log').mockImplementation((...args: unknown[]) => {
      logged.push(args.join(' '));
    });

    await createVerifyPR(proofDir, results, [], dir, { dryRun: true, quiet: false });

    const output = logged.join('\n');
    expect(output).toContain('Verify: my-feature');
    expect(output).toContain('gh pr create');
    logSpy.mockRestore();
  });

  test('PR title follows pattern Verify: <proof-dir-basename>', () => {
    const proofDir = '/repo/.forge/proofs/gtmeng-590';
    const title = `Verify: ${path.basename(proofDir)}`;
    expect(title).toBe('Verify: gtmeng-590');
  });

  test('PR title uses last component of nested proofDir', () => {
    expect(`Verify: ${path.basename('/deep/nested/proof/dir')}`).toBe('Verify: dir');
    expect(`Verify: ${path.basename('/repo/.forge/proofs/my-feature')}`).toBe('Verify: my-feature');
  });

  test('gh error is surfaced gracefully without throwing', async () => {
    const dir = await makeTmpDir();
    const results = [makeResult({ status: 'pass' })];

    // dir is not a git repo, so gh pr create will fail
    // createVerifyPR should catch the error and not throw
    await createVerifyPR(dir, results, [], dir, { quiet: false });

    // Should not have set exitCode to 1 (gh failure is not a verify failure)
    // The function returns without throwing
    expect(process.exitCode).not.toBe(1);
  });

  test('gh error prints failure message when not quiet', async () => {
    const dir = await makeTmpDir();
    const results = [makeResult({ status: 'pass' })];
    const logged: string[] = [];
    const logSpy = spyOn(console, 'log').mockImplementation((...args: unknown[]) => {
      logged.push(args.join(' '));
    });

    await createVerifyPR(dir, results, [], dir, { quiet: false });

    const output = logged.join('\n');
    expect(output).toContain('PR creation failed');
    logSpy.mockRestore();
  });

  test('gh error is silent in quiet mode', async () => {
    const dir = await makeTmpDir();
    const results = [makeResult({ status: 'pass' })];
    const logSpy = spyOn(console, 'log').mockImplementation(() => {});

    await createVerifyPR(dir, results, [], dir, { quiet: true });

    // In quiet mode, no output even on failure
    expect(logSpy).not.toHaveBeenCalled();
    logSpy.mockRestore();
  });

  test('failure summary lists failed test files when not quiet', async () => {
    const dir = await makeTmpDir();
    const results = [
      makeResult({ testFile: 'auth.test.ts', status: 'fail' }),
      makeResult({ testFile: 'api.test.ts', status: 'fail' }),
    ];
    const logged: string[] = [];
    const logSpy = spyOn(console, 'log').mockImplementation((...args: unknown[]) => {
      logged.push(args.join(' '));
    });

    await createVerifyPR(dir, results, [], dir, { quiet: false });

    const output = logged.join('\n');
    expect(output).toContain('PR creation skipped');
    expect(output).toContain('2 test file(s) failed');
    expect(output).toContain('auth.test.ts');
    expect(output).toContain('api.test.ts');
    logSpy.mockRestore();
  });

  test('cleans up temp file even when gh fails', async () => {
    const dir = await makeTmpDir();
    const results = [makeResult({ status: 'pass' })];

    await createVerifyPR(dir, results, [], dir, { quiet: true });

    // After the function returns, temp files should be cleaned up
    // We can't directly check since the temp file name is dynamic,
    // but we can verify the function completed without error
    const tmpFiles = await fs.readdir(os.tmpdir());
    const verifyTmpFiles = tmpFiles.filter(f => f.startsWith('forge-verify-pr-'));
    // All forge-verify-pr temp files should be cleaned up
    // (there might be 0 — cleanup happened in finally block)
    expect(verifyTmpFiles.length).toBeLessThanOrEqual(0);
  });
});

